// Ref: #/components/schemas/ModifyUserInput
type ModifyUserInput struct {
	// The amount of kudos to modify (can be negative).
	Kudos OptFloat64 `json:"kudos"`
	// The amount of concurrent request this user can have.
	Concurrency OptInt `json:"concurrency"`
	// The amount by which to multiply the users kudos consumption.
	UsageMultiplier OptFloat64 `json:"usage_multiplier"`
	// Set to the amount of workers this user is allowed to join to the horde when in worker invite-only
	// mode.
	WorkerInvited OptInt `json:"worker_invited"`
	// Set to true to make this user a horde moderator.
	Moderator OptBool `json:"moderator"`
	// Set to true to make this user display their worker IDs.
	PublicWorkers OptBool `json:"public_workers"`
	// When specified, will start assigning the user monthly kudos, starting now!.
	MonthlyKudos OptInt `json:"monthly_kudos"`
	// When specified, will change the username. No profanity allowed!.
	Username OptString `json:"username"`
	// When set to true,the user and their servers will not be affected by suspicion.
	Trusted OptBool `json:"trusted"`
	// When set to true, the user cannot tranfer kudos and all their workers are put into permanent
	// maintenance.
	Flagged OptBool `json:"flagged"`
	// When set to true, the user will be able to serve custom Stable Diffusion models which do not exist
	// in the Official AI Horde Model Reference.
	Customizer OptBool `json:"customizer"`
	// When set to true, the user will be able to onboard workers behind a VPN. This should be used as a
	// temporary solution until the user is trusted.
	Vpn OptBool `json:"vpn"`
	// When set to true, the user is considered a service account proxying the requests for other users.
	Service OptBool `json:"service"`
	// When set to true, the user is considered an education account and some options become more
	// restrictive.
	Education OptBool `json:"education"`
	// When set to true, The user can send special payloads.
	Special OptBool `json:"special"`
	// When set to true, A user's who's marked to be deleted will become active again.
	Undelete OptBool `json:"undelete"`
	// When set to true, the replacement filter will always be applied against this user.
	Filtered OptBool `json:"filtered"`
	// Set the user's suspicion back to 0.
	ResetSuspicion OptBool `json:"reset_suspicion"`
	// (Re)Generate a service account proxy passkey.
	GenerateProxyPasskey OptBool `json:"generate_proxy_passkey"`
	// Contact details for the horde admins to reach the user in case of emergency. This is only visible to
	// horde moderators.
	Contact OptString `json:"contact"`
	// Add further information about this user for the other admins.
	AdminComment OptString `json:"admin_comment"`
}

